import React from 'react';
import { createRoot } from 'react-dom/client';
import { Provider } from 'react-redux';
import singleSpaReact from 'single-spa-react';
import { SilentModeButton, toggleSilentMode } from '@linm-soft/common-components';
import { notificationStore } from '../store/store';
import { useDispatch, useSelector } from 'react-redux';
import type { NotificationRootState } from '../store/store';

const SilentModeConnected: React.FC = () => {
  const dispatch  = useDispatch();
  const isSilent  = useSelector((s: NotificationRootState) => s.ui.silentMode);
  return <SilentModeButton isSilent={isSilent} onToggle={() => dispatch(toggleSilentMode())} />;
};

const SilentModeWithProvider: React.FC = () => (
  <Provider store={notificationStore}>
    <SilentModeConnected />
  </Provider>
);

export const SilentModeParcel = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: SilentModeWithProvider,
  renderType: 'createRoot',
  errorBoundary(error) { throw error; },
});
