import React, { useEffect } from 'react';
import {
  useSignalREvent,
  HubEvent,
  pushNotification,
  fetchUnreadCount,
  signalRService,
  hasValidAuthToken,
} from '@linm-soft/common-components';
import { notificationStore } from '../store/store';
import { appSettings } from '../config/appSettings';

function dispatchToast(notif: { title: string; message: string; priority?: string }) {
  const silent = notificationStore.getState().ui.silentMode;
  if (silent) return;
  window.dispatchEvent(
    new CustomEvent('linm:notification:toast', {
      detail: notif,
    }),
  );
}

function dispatchBrowserNotification(notif: {
  title: string;
  message: string;
  id?: string;
  actionUrl?: string;
}) {
  if (appSettings.pushProvider !== 'none') return;
  window.dispatchEvent(
    new CustomEvent('linm:notification:browser', {
      detail: notif,
    }),
  );
}

/** Broadcast to host MFEs that still render full notification pages (e.g. /notifications). */
function broadcastReceived(notif: unknown) {
  window.dispatchEvent(new CustomEvent('linm:notification:received', { detail: notif }));
}

/** SignalR + badge sync — owned exclusively by @linm/notification lifecycle. */
export const NotificationLifecycleBridge: React.FC = () => {
  useEffect(() => {
    if (hasValidAuthToken()) {
      notificationStore.dispatch(fetchUnreadCount());
    }

    const onAuth = (e: Event) => {
      const { token } = (e as CustomEvent<{ token: string | null }>).detail;
      if (token) notificationStore.dispatch(fetchUnreadCount());
    };
    window.addEventListener('linm:auth:token-changed', onAuth);

    const onVisibility = () => {
      if (document.visibilityState === 'visible' && hasValidAuthToken()) {
        notificationStore.dispatch(fetchUnreadCount());
      }
    };
    document.addEventListener('visibilitychange', onVisibility);

    const offReconnect = signalRService.onReconnected(() => {
      notificationStore.dispatch(fetchUnreadCount());
    });

    return () => {
      window.removeEventListener('linm:auth:token-changed', onAuth);
      document.removeEventListener('visibilitychange', onVisibility);
      offReconnect?.();
    };
  }, []);

  useSignalREvent(HubEvent.ReceiveNotification, (notif) => {
    if (notif.type === 'NEW_MESSAGE') return;

    notificationStore.dispatch(pushNotification(notif));
    broadcastReceived(notif);
    dispatchToast({ title: notif.title, message: notif.message, priority: notif.priority });
    dispatchBrowserNotification({
      title: notif.title,
      message: notif.message,
      id: notif.id,
      actionUrl: notif.actionUrl,
    });
  });

  useSignalREvent(HubEvent.DeptNotification, (notif) => {
    notificationStore.dispatch(pushNotification(notif));
    broadcastReceived(notif);
    dispatchToast({ title: notif.title, message: notif.message, priority: notif.priority });
    dispatchBrowserNotification({
      title: notif.title,
      message: notif.message,
      id: `dept-${notif.id}`,
      actionUrl: notif.actionUrl,
    });
  });

  return null;
};
